var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hngh...","TWN":"嗯……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"정신이 드시나요?","JPN":"気が付きましたか？","ENG":"Ah, you woke up.","TWN":"您醒了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......여, 여긴? 제가 어떻게 된 거죠?","JPN":"……こ、ここは？　いったいどうなっているのです？","ENG":"W-where am I? What happened to me?","TWN":"……這、這裡是？我怎麼了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"서재 바닥에 쓰러져 계셨어요.","JPN":"書斎で倒れていらしたんですよ。","ENG":"You were found lying on the floor in the library.","TWN":"您倒在書齋的地板上了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"긴장이 풀리면서 그동안 쌓인 피로가 몰려 온 것 같아요.","JPN":"緊張が解けて、溜まっていた疲れが出たのでしょう。","ENG":"It looks like you collapsed from fatigue after your long journey.","TWN":"似乎是放鬆之後，這陣子累積的疲勞一口氣湧上來了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런......","JPN":"そんな……","ENG":"That’s...","TWN":"怎麼會……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐, 그 괴물들!","JPN":"そう、あの怪物たちは？","ENG":"Wait, those monsters!","TWN":"等一下，那些怪物！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제게 달려들던 그것들은 어떻게 됐죠?!","JPN":"私に襲い掛かったあの怪物はどうなったのです！？","ENG":"What happened to the monsters that were converging on me?","TWN":"向我殺來的那些東西怎麼樣了？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"괴물이요? 그런 건 못 봤는데요?","JPN":"怪物？　そのようなものは見ていませんが？","ENG":"Monsters? No, there weren't any monsters.","TWN":"怪物嗎？我們沒有看見那種東西啊？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"아, 혹시 저택에서 기르는 아이들을 착각하신 것 아닐까요?","JPN":"ああ、もしかしたら邸宅で暮らす子たちを見間違えたのかもしれませんね。","ENG":"Ah, is there a chance you're talking about the babies we have at the mansion?","TWN":"啊，莫非您把宅邸裡養著的孩子們搞錯成怪物了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"레지나 님을 발견했을 때도 그 아이들에게 둘러싸인 채 계셨답니다.","JPN":"レジーナ様を見つけた時、あの子たちに囲まれていましたから。","ENG":"You were surrounded by them when you were found.","TWN":"我們發現蕾佳娜大人的時候，您正被那群孩子們圍著呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아이들?","JPN":"あの子たち？","ENG":"Babies?","TWN":"孩子？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"얼굴이 끈적거리는데...... 혹시 개나 고양이인가요?","JPN":"この顔のべたつき……もしや、犬か猫ですか？","ENG":"Ew, my face feels wet. Oh, are they animals, like dogs or cats?","TWN":"我記得他們臉上黏黏濕濕的……是小狗還是小貓嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"네. 비슷해요.","JPN":"ええ。似たようなものです。","ENG":"You could say that.","TWN":"是的，類似吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"말랑말랑하고 애교도 잘 부리는, 굉장히 깜찍한 아이들이랍니다.","JPN":"ふわふわで愛嬌もあって、とても可愛い子たちなんですよ。","ENG":"They feel soft to the touch and know how to act cute.","TWN":"那群孩子們不但軟綿綿的，又愛撒嬌，非常可愛喔。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"평소에는 낯가림이 심한데 레지나 님 앞에서는 무척 활기차더라고요.","JPN":"普段は人見知りをするのですけど、レジーナ様の前ではとても元気でした。","ENG":"They're normally very shy, but it seemed they were comfortable around you.","TWN":"平時可是非常怕生，但是在蕾佳娜大人面前反常的很有活力。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"아마 레지나 님과 상성이 잘 맞나 봐요.","JPN":"きっと、レジーナ様と相性が良いのでしょう。","ENG":"Maybe they like being around you.","TWN":"看來和蕾佳娜大人非常合得來呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그래요?","JPN":"そ、そうですの？","ENG":"R-really?","TWN":"是、是嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"신기하네요. 전 몸이 차가워선지 동물들에게 다가가면 다들 피하거든요.","JPN":"不思議ですわ。私は体が冷たいせいか、動物に近寄ると逃げられることが多いのです。","ENG":"That's odd. My body is cold, and animals don't like it when I approach them.","TWN":"真是神奇啊。因為我身體比較冷，只要靠近小動物，牠們都會躲開的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"마음껏 쓰다듬을 수 있는 좋은 기회였는데 하필 정신을 잃고 있었다니......","JPN":"存分に撫でることができるチャンスでしたのに、気を失うなんて……","ENG":"No, it was my chance to stroke them all I want, and I was unconscious.","TWN":"明明剛剛是個可以盡情陪陪他們的好機會，偏偏我失去了意識……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시 괜찮으면 저도 쓰다듬어 볼 수 있을까요?","JPN":"もしよろしければ、私にも撫でさせていただけませんか？","ENG":"Can I do it later, if it's okay?","TWN":"如果可以的話，我還可以陪陪他們摸摸他們嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"후훗. 다음에 정식으로 소개해 드릴게요.","JPN":"ふふっ、また今度……改めて紹介しますね。","ENG":"Fu fu. You'll have the chance to meet them later.","TWN":"呵呵，下次我們會正式為您介紹他們的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"레지나 님께서도 무척 좋아하시게 될 거예요.","JPN":"レジーナ様にも、きっと気に入っていただけると思います。","ENG":"And you'll like them very much, Miss Regina.","TWN":"蕾佳娜大人一定也會非常喜歡的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고마워요. 그런데......","JPN":"ありがとうございます。ところで……","ENG":"Thank you. So...","TWN":"謝謝妳。不過……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 누구죠?","JPN":"あなたは誰ですか？","ENG":"Who are you?","TWN":"妳是誰啊？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 지역 주민 같진 않은데 왜 저택에 있는 건가요?","JPN":"この地域の住民ではないようですが、なぜこの邸宅に？","ENG":"You don't seem like a resident in the area. What brings you to the mansion?","TWN":"妳看起來不像這附近的居民，為什麼會在宅邸裡？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"아, 죄송해요.","JPN":"ああ、失礼いたしました。","ENG":"Oh, sorry.","TWN":"啊，非常抱歉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"놀라서 그만 인사 드린다는 것도 까맣게 잊고 있었네요.","JPN":"驚いたせいでご挨拶が遅れてしまいましたね。","ENG":"All this commotion left us no time for introduction","TWN":"因為嚇了一跳，連問候都忘得一乾二淨了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 부인의 뒤를 이은 신임 학회장, 에델 마이트너랍니다.","JPN":"マクレディー夫人の後を引き継いだ新任学会長、エデル・マイトナーと申します。","ENG":"Edel Meitner. The new President of the Society, after Mrs. MacCready.","TWN":"是繼麥克蕾蒂 夫人之後的新任學會長艾瑟兒·邁特納。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"고향에 돌아오신 걸 환영해요. 레지나 님.","JPN":"故郷へお帰りなさいませ、レジーナ様。","ENG":"Welcome home, Miss Regina.","TWN":"歡迎您回到家鄉，蕾佳娜大人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};